+            if (isParameterCalledInExpr(sub.value.*, param_name)) return true;
+            return switch (sub.slice) {
+                .index => |idx| isParameterCalledInExpr(idx.*, param_name),
+                .slice => |sr| {
+                    if (sr.lower) |l| if (isParameterCalledInExpr(l.*, param_name)) return true;
