+            }
+            for (d.values) |v| {
+                if (isParameterCalledInExpr(v, param_name)) return true;
+            }
+            return false;
+        },
+        .fstring => |fs| {
+            for (fs.parts) |part| {
+                switch (part) {
+                    .expr => |e| if (isParameterCalledInExpr(e.node.*, param_name)) return true,
